#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    const __global float *power,
    const __global float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int blockCols = (col + borderCols - 1) / borderCols;
    int blockRows = (row + borderRows - 1) / borderRows;

    int blockIdx = get_block_id(0);
    int blockY = get_block_id(1);

    int blockStartX = blockIdx * borderCols;
    int blockStartY = blockY * borderRows;

    int localX = get_local_id(0);
    int localY = get_local_id(1);

    int globalX = blockStartX + localX;
    int globalY = blockStartY + localY;

    int r = globalY;
    int c = globalX;

    if (r >= row || c >= col) return;

    float delta;
    int idx = r * col + c;

    // Boundary conditions
    if (r == 0 && c == 0) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == 0 && c == col - 1) {
        delta = Cap_1 * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row - 1 && c == col - 1) {
        delta = Cap_1 * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row - 1 && c == 0) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == 0) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == col - 1) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row - 1) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == 0) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else {
        // Interior points
        delta = Cap_1 * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }

    result[idx] = temp[idx] + delta;
}
